export function searchProducts(query) {
  if (!query || query.trim().length === 0) return [];
  const q = query.toLowerCase().trim();
  return products.filter(p => p.name.toLowerCase().includes(q));
}

export function findProduct(id) {
  return products.find(p => p.id === id);
}

export function calculateNutrients(product, grams) {
  const factor = grams / 100;
  return {
    calories: Math.round(product.calories * factor),
    protein: +(product.protein * factor).toFixed(1),
    fat: +(product.fat * factor).toFixed(1),
    carbs: +(product.carbs * factor).toFixed(1)
  };
}

export function sumNutrients(nutrientArray) {
  return nutrientArray.reduce((acc, n) => ({
    calories: acc.calories + n.calories,
    protein: +(acc.protein + n.protein).toFixed(1),
    fat: +(acc.fat + n.fat).toFixed(1),
    carbs: +(acc.carbs + n.carbs).toFixed(1)
  }), { calories: 0, protein: 0, fat: 0, carbs: 0 });
}

export { products, categories };